import { FastifyPluginAsyncTypebox } from "@fastify/type-provider-typebox";
import {
  createUserSchema,
  getAllUsersSchema,
  getUserSchema,
  updateUserSchema,
  deleteUserSchema,
  CreateUserDto,
  UpdateUserDto,
  UserParams
} from "./users.schema";
import { FastifyInstance } from "fastify";

const usersRoutes: FastifyPluginAsyncTypebox = async (fastify: FastifyInstance) => {

  fastify.post<{ Body: CreateUserDto }>(
    "/",
    {
      preHandler: [fastify.checkToken],
      schema: createUserSchema
    },
    async (request, reply) => {
      try {
        const user = await fastify.usersService.createUser(request.body);
        return reply.code(201).send(user);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(400).send({ error: "Error creating user" });
      }
    }
  );

  // GET ALL
  fastify.get(
    "/",
    {
      preHandler: [fastify.checkToken],
      schema: getAllUsersSchema
    },
    async (_, reply) => {
      const users = await fastify.usersService.getUsers();
      return reply.send(users);
    }
  );

  fastify.get<{ Params: UserParams }>(
    "/:id",
    {
      preHandler: [fastify.checkToken],
      schema: getUserSchema
    },
    async (request, reply) => {
      const user = await fastify.usersService.getUserById(request.params.id);
      if (!user) {
        return reply.code(404).send({ error: "User not found" });
      }
      return reply.send(user);
    }
  );

  fastify.put<{ Params: UserParams; Body: UpdateUserDto }>(
    "/:id",
    {
      preHandler: [fastify.checkToken],
      schema: updateUserSchema
    },
    async (request, reply) => {
      try {
        const user = await fastify.usersService.updateUser(
          request.params.id,
          request.body
        );
        return reply.send(user);
      } catch (err) {
        fastify.log.error(err);
        return reply.code(400).send({ error: "Error updating user" });
      }
    }
  );

  fastify.delete<{ Params: UserParams }>(
    "/:id",
    {
      preHandler: [fastify.checkToken],
      schema: deleteUserSchema
    },
    async (request, reply) => {
      await fastify.usersService.deleteUser(request.params.id);
      return reply.status(204).send();
    }
  );
};

export default usersRoutes;

import { Type } from '@sinclair/typebox';
import type { FastifyPluginAsyncTypebox } from '@fastify/type-provider-typebox';

const healthRoutes: FastifyPluginAsyncTypebox = async (fastify) => {
  // Health check endpoint
  fastify.get(
    '/health',
    {
      schema: {
        description: 'Health check endpoint',
        tags: ['Health'],
        response: {
          200: Type.Object({
            status: Type.Literal('ok'),
            timestamp: Type.String(),
            uptime: Type.Number(),
            environment: Type.String(),
          }),
        },
      },
    },
    async (_request, reply) => {
      return reply.send({
        status: 'ok',
        timestamp: new Date().toISOString(),
        uptime: process.uptime(),
        environment: process.env.NODE_ENV || 'development',
      });
    }
  );

  // Readiness check endpoint
  fastify.get(
    '/ready',
    {
      schema: {
        description: 'Readiness check endpoint - checks database connection',
        tags: ['Health'],
        response: {
          200: Type.Object({
            status: Type.Literal('ready'),
            services: Type.Object({
              database: Type.Boolean(),
            }),
            timestamp: Type.String(),
          }),
          503: Type.Object({
            status: Type.Literal('not_ready'),
            services: Type.Object({
              database: Type.Boolean(),
            }),
            timestamp: Type.String(),
          }),
        },
      },
    },
    async (_request, reply) => {
      let isDatabaseReady = false;

      try {
        // Check database connection
        await fastify.prisma.$queryRaw`SELECT 1`;
        isDatabaseReady = true;
      } catch (err) {
        fastify.log.error({ err }, 'Database health check failed');
      }

      const status = isDatabaseReady ? 'ready' : 'not_ready';
      const statusCode = isDatabaseReady ? 200 : 503;

      return reply.status(statusCode).send({
        status,
        services: {
          database: isDatabaseReady,
        },
        timestamp: new Date().toISOString(),
      });
    }
  );
};

export default healthRoutes;

