const fp = require('fastify-plugin')
const CacheManager = require('cache-manager')
const ms = require('ms')
const onEnd = require('on-http-end')
const getKeys = require('./get-keys')

const X_CACHE_EXPIRE = 'x-cache-expire'
const X_CACHE_TIMEOUT = 'x-cache-timeout'
const X_CACHE_HIT = 'x-cache-hit'

const plugin = (fastify, opts, next) => {
  opts = Object.assign({
    stores: [CacheManager.caching({ store: 'memory', max: 1000, ttl: 30 })]
  }, opts)

  // creating multi-cache instance
  const multiCache = CacheManager.multiCaching(opts.stores)

  fastify.addHook('onRequest', (request, reply, next) => {
    const { res } = reply
    const { req } = request

    onEnd(res, (payload) => {
      // avoid double caching
      if (req.cacheHit) return

      if (payload.headers[X_CACHE_EXPIRE]) {
        // support service level expiration
        const keysPattern = payload.headers[X_CACHE_EXPIRE]
        // delete keys on all cache tiers
        opts.stores.forEach(cache => getKeys(cache, keysPattern).then(keys => multiCache.del(keys)))
      } else if (payload.headers[X_CACHE_TIMEOUT]) {
        // we need to cache response
        multiCache.set(req.cacheKey, JSON.stringify(payload), {
          // @NOTE: cache-manager uses seconds as TTL unit
          // restrict to min value "1 second"
          ttl: Math.max(ms(payload.headers[X_CACHE_TIMEOUT]), 1000) / 1000
        })
      }
    })

    return next()
  })

  fastify.addHook('preHandler', async (request, reply) => {
    const { req } = request
    if (req.cacheDisabled) return

    let { url, cacheAppendKey = req => '' } = req
    cacheAppendKey = await cacheAppendKey(req)

    const key = req.method + url + cacheAppendKey
    // ref cache key on req object
    req.cacheKey = key
    const cached = await get(multiCache, key)
    if (!cached) return

    // respond from cache if there is a hit
    let { status, headers, data } = JSON.parse(cached)
    if (typeof data === 'object' && data.type === 'Buffer') {
      data = Buffer.from(data.data)
    }
    headers[X_CACHE_HIT] = '1'

    // set cached response headers
    Object.keys(headers).forEach(header => reply.header(header, headers[header]))

    // send cached payload
    req.cacheHit = true
    reply.code(status).send(data)
  })

  return next()
}

const get = (cache, key) => new Promise((resolve) => {
  cache.getAndPassUp(key, (_, res) => {
    resolve(res)
  })
})

module.exports = fp(plugin)

import { CronJob, CronJobParameters } from 'cron'
import type { FastifyInstance, FastifyPluginAsync } from 'fastify'
import fp from 'fastify-plugin'

export type Job = CronJob & {
  readonly name?: string
}

declare module 'fastify' {
  interface FastifyInstance {
    cron: CronDecorator
  }
}

export type Params = Omit<CronJobParameters, 'onTick' | 'onComplete'> & {
  onTick: (server: FastifyInstance) => void
  onComplete?: (server: FastifyInstance) => void
  startWhenReady?: boolean
  name?: string
}

export interface CronDecorator {
  readonly jobs: Job[]
  createJob: (params: Params) => Job
  getJobByName: (name: string) => Job | undefined
  startAllJobs: () => void
  stopAllJobs: () => void
}

export type FalsyValue = undefined | null | false

export interface Config {
  jobs?: (Params | FalsyValue)[]
}

const plugin: FastifyPluginAsync<Config> = async function fastifyCronPlugin(
  server,
  opts
) {
  const decorator: CronDecorator = {
    jobs: [],
    createJob: function createJob(params) {
      const innerParams: CronJobParameters = {
        ...params,
        onTick: () => params.onTick(server),
        onComplete: () =>
          typeof params.onComplete === 'function'
            ? () => params.onComplete!(server)
            : undefined
      }
      const job: Job = Object.assign(new CronJob(innerParams), {
        name: params.name
      })
      if (params.startWhenReady === true) {
        server.ready(() => job.start())
      }
      decorator.jobs.push(job)
      return job
    },
    getJobByName: function getJobByName(name) {
      return decorator.jobs.find(j => j.name === name)
    },
    startAllJobs: function startAllJobs() {
      decorator.jobs.forEach(job => job.start())
    },
    stopAllJobs: function stopAllJobs() {
      decorator.jobs.forEach(job => job.stop())
    }
  }
  for (const params of opts.jobs || []) {
    if (params) {
      decorator.createJob(params)
    }
  }

  server.decorate('cron', decorator)
  server.addHook('onClose', () => decorator.stopAllJobs())
}

export default fp(plugin, {
  name: 'fastify-cron',
  fastify: '4.x || 5.x'
})

'use strict'

const Fastify = require('fastify')
const mercurius = require('..')

// Define the constraint custom strategy
const schemaStrategy = {
  name: 'schema',
  storage: function () {
    const handlers = {}
    return {
      get: (type) => { return handlers[type] || null },
      set: (type, store) => { handlers[type] = store }
    }
  },
  deriveConstraint: (req, ctx) => {
    return req.headers.schema
  },
  validate: () => true,
  mustMatchWhenDerived: true
}

// Initialize fastify
const app = Fastify({ constraints: { schema: schemaStrategy } })

// Schema 1 definition
const schema = `
  type Query {
    add(x: Int, y: Int): Int
  }
`

const resolvers = {
  Query: {
    add: async (_, obj) => {
      const { x, y } = obj
      return x + y
    }
  }
}

// Schema A registration with A constraint
app.register(async childServer => {
  childServer.register(mercurius, {
    schema,
    resolvers,
    graphiql: false,
    routes: false
  })

  childServer.route({
    path: '/',
    method: 'POST',
    constraints: { schema: 'A' },
    handler: (req, reply) => {
      const query = req.body
      return reply.graphql(query)
    }
  })
})

const schema2 = `
  type Query {
    subtract(x: Int, y: Int): Int
  }
`

const resolvers2 = {
  Query: {
    subtract: async (_, obj) => {
      const { x, y } = obj
      return x - y
    }
  }
}

app.register(async childServer => {
  childServer.register(mercurius, {
    schema: schema2,
    resolvers: resolvers2,
    graphiql: false,
    routes: false
  })

  childServer.route({
    path: '/',
    method: 'POST',
    constraints: { schema: 'B' },
    handler: (req, reply) => {
      const query = req.body
      return reply.graphql(query)
    }
  })
})

app.listen({ port: 3000 })

import * as bcrypt from 'bcryptjs';
import { PrismaClient } from '@prisma/client';
import * as JWT from 'jsonwebtoken';
import Joi from 'joi';
import { FastifyReply, FastifyRequest } from 'fastify';

export const prisma = new PrismaClient();

export const utils = {
  isJSON: (data: string) => {
    try {
      JSON.parse(data);
    } catch (e) {
      return false;
    }
    return true;
  },

  getTime: (): number => {
    return new Date().getTime();
  },

  genSalt: (saltRounds: number, value: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      bcrypt.genSalt(saltRounds, (err, salt) => {
        if (err) return reject(err);
        bcrypt.hash(value, salt, (err, hash) => {
          if (err) return reject(err);
          resolve(hash);
        });
      });
    });
  },

  compareHash: (hash: string, value: string): Promise<boolean> => {
    return new Promise((resolve, reject) => {
      bcrypt.compare(value, hash, (err, result) => {
        if (err) return reject(err);
        resolve(result);
      });
    });
  },

  healthCheck: async (): Promise<void> => {
    try {
      await prisma.$queryRaw`SELECT 1`;
    } catch (e) {
      throw new Error(`Health check failed: ${e.message}`);
    }
  },

  getTokenFromHeader: (
    authorizationHeader: string | undefined,
  ): string | null => {
    if (!authorizationHeader) return null;
    const token = authorizationHeader.replace('Bearer ', '');
    return token || null;
  },

  verifyToken: (token: string): any => {
    try {
      return JWT.verify(token, process.env.APP_JWT_SECRET as string);
    } catch (err) {
      return null;
    }
  },

  validateSchema: (schema: Joi.ObjectSchema) => {
    return (data: any) => {
      const { error } = schema.validate(data);
      if (error) {
        throw new Error(error.details[0].message);
      }
    };
  },

  preValidation: (schema: Joi.ObjectSchema) => {
    return (
      request: FastifyRequest,
      reply: FastifyReply,
      done: (err?: Error) => void,
    ) => {
      const { error } = schema.validate(request.body);
      if (error) {
        return done(error);
      }
      done();
    };
  },
};

